module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output [15:0] result
);
// TODO: Implement DIV module
`define S_IDLE 0
`define S_DIVIDE 1
`define S_DONE 2
reg [1:0] state, next_state;
reg [15:0] dividend_reg, divisor_reg;
reg [15:0] SR, next_SR;
reg [4:0] cnt, next_cnt;
reg [16:0] SUB, next_SUB;
reg [15:0] NEG_DIVISOR, next_NEG_DIVISOR;
reg [15:0] result_reg, next_result_reg;
reg next_res_valid;
assign result = result_reg;
always @(*) begin
    if (rst) begin
        next_SR = 0;
        next_cnt = 0;
        next_SUB = 0;
        next_NEG_DIVISOR = 0;
        next_result_reg = 0;
        next_state = `S_IDLE;
        next_res_valid = 0;
    end
    else begin
        case (state)
            `S_IDLE: begin
                if (opn_valid & ~res_valid) begin
                    next_SR = {1'b0, dividend};
                    next_cnt = 0;
                    next_SUB = {1'b0, divisor};
                    next_NEG_DIVISOR = ~{1'b0, divisor} + 1;
                    next_result_reg = 0;
                    next_state = `S_DIVIDE;
                    next_res_valid = 0;
                end
                else begin
                    next_SR = 0;
                    next_cnt = 0;
                    next_SUB = 0;
                    next_NEG_DIVISOR = 0;
                    next_result_reg = 0;
                    next_state = `S_IDLE;
                    next_res_valid = 0;
                end
            end
            `S_DIVIDE: begin
                if (cnt[4]) begin
                    next_SR = {SR[14:0], (SR[15] ^ NEG_DIVISOR[0])};
                    next_cnt = 0;
                    next_SUB = {SUB[15:0], SR[15]};
                    next_NEG_DIVISOR = {NEG_DIVISOR[14:0], 1'b0};
                    next_result_reg = SR[15:0];
                    next_state = `S_DONE;
                    next_res_valid = 0;
                end
                else begin
                    next_SR = {SR[14:0], (SR[15] ^ NEG_DIVISOR[0])};
                    next_cnt = cnt + 1;
                    next_SUB = {SUB[15:0], SR[15]};
                    next_NEG_DIVISOR = {NEG_DIVISOR[14:0], 1'b0};
                    next_result_reg = 0;
                    next_state = `S_DIVIDE;
                    next_res_valid = 0;
                end
            end
            `S_DONE: begin
                next_SR = 0;
                next_cnt = 0;
                next_SUB = 0;
                next_NEG_DIVISOR = 0;
                next_result_reg = result_reg;
                next_state = `S_IDLE;
                next_res_valid = 1;
            end
        endcase
    end
end
always @(posedge clk or negedge rst) begin
    if (!rst) begin
        SR <= 0;
        cnt <= 0;
        SUB <= 0;
        NEG_DIVISOR <= 0;
        result_reg <= 0;
        state <= `S_IDLE;
        res_valid <= 0;
    end
    else begin
        SR <= next_SR;
        cnt <= next_cnt;
        SUB <= next_SUB;
        NEG_DIVISOR <= next_NEG_DIVISOR;
        result_reg <= next_result_reg;
        state <= next_state;
        res_valid <= next_res_valid;
    end
end
endmodule

module width_8to16
