module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

reg [2:0] cnt;
reg [3:0] data;
reg valid;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 3'b0;
    end else begin
        if (cnt == 3'b11) begin
            cnt <= 3'b0;
        end else begin
            cnt <= cnt + 1'b1;
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data <= 4'b0;
    end else begin
        if (cnt == 3'b11) begin
            data <= d;
        end else begin
            data <= {data[2:0], data[3]};
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        valid <= 1'b0;
    end else begin
        if (cnt == 3'b11) begin
            valid <= 1'b1;
        end else begin
            valid <= 1'b0;
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule

module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);
    reg [15:0] a_reg, b_reg;
    reg [15:0] result_reg, odd_reg;

    always @(A, B) begin
        a_reg = A;
        b_reg = B;
    end

    always @(a_reg, b_reg) begin
        result_reg = 0;
        odd_reg = a_reg;

        for (int i = 0; i < 16; i = i + 1) begin
            if (odd_reg[15:8] >= b_reg) begin
                result_reg[i] = 1;
                odd_reg = {odd_reg[14:0], a_reg[15-i]};
            end else begin
                result_reg[i] = 0;
                odd_reg = {odd_reg[14:0], a_reg[15-i]};
            end
        end
    end

    assign result = result_reg;
    assign odd = odd_reg;
endmodule

module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    reg [15:0] partial_product;
    integer i;

    always @(*) begin
        multiplicand = A;
        multiplier = B;
        partial_product = 0;

        for (i = 0; i < 8; i = i + 1) begin
            if (multiplier[i] == 1) begin
                partial_product = partial_product + (multiplicand << i);
            end
        end

        product = partial_product;
    end

endmodule

module fsm
(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);
    // Define states
    parameter S0 = 4'b0000;
    parameter S1 = 4'b0001;
    parameter S2 = 4'b0010;
    parameter S3 = 4'b0011;
    parameter S4 = 4'b0100;
    parameter S5 = 4'b0101;
    parameter S6 = 4'b0110;
    parameter S7 = 4'b0111;
    parameter S8 = 4'b1000;
    // Define state register
    reg [3:0] state;
    reg [3:0] next_state;
    // Define match register
    reg match_reg;
    // Sequential logic block triggered on the positive edge of CLK or the negative edge of RST
    always @(posedge CLK or negedge RST) begin
        if (!RST) begin
            state <= S0;
            MATCH <= 1'b0;
        end else begin
            state <= next_state;
        end
    end
    // Combinational logic block triggered on the change of IN or state
    always @(IN or state) begin
        if (IN == 1'b1) begin
            case (state)
                S0: begin
                    next_state = S1;
                    match_reg = 1'b0;
                end
                S1: begin
                    next_state = S2;
                    match_reg = 1'b0;
                end
                S2: begin
                    next_state = S3;
                    match_reg = 1'b0;
                end
                S3: begin
                    next_state = S4;
                    match_reg = 1'b0;
                end
                S4: begin
                    next_state = S1;
                    match_reg = 1'b1;
                end
                S5: begin
                    next_state = S1;
                    match_reg = 1'b0;
                end
                S6: begin
                    next_state = S3;
                    match_reg = 1'b0;
                end
                S7: begin
                    next_state = S4;
                    match_reg = 1'b0;
                end
                S8: begin
                    next_state = S1;
                    match_reg = 1'b0;
                end
                default: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
            endcase
        end else begin
            case (state)
                S0: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S1: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S2: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S3: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S4: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                default: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
            endcase
        end
    end
    assign MATCH = match_reg;
endmodule

