            cnt_10 <= cnt_10 + 4'b1;
        end

        // CLK_1 generation
        if (cnt_100 == 7'd49) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 7'b0;
        end
        else begin
            cnt_100 <= cnt_100 + 7'b1;
        end
    end
end
