module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
    parameter size = 4;
    reg [size-1:0] sum_reg [0:size-1];
    reg [size-1:0] carry_reg [0:size-1];
    reg [size-1:0] sum_reg_next;
    reg [size-1:0] carry_reg_next;
    reg [size-1:0] extension_a;
    reg [size-1:0] extension_b;
    reg [size-1:0] partial_product;
    integer i;
    always @(*) begin
        extension_a = {size{1'b0}};
        extension_b = {size{1'b0}};
        for (i = 0; i < size; i = i + 1) begin
            if (i == 0) begin
                extension_a = mul_a;
                extension_b = mul_b;
            end
            else begin
                extension_a = {extension_a[size-2:0], 1'b0};
                extension_b = {extension_b[size-2:0], 1'b0};
            end
            partial_product[i] = extension_a[i] & extension_b[i];
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < size; i = i + 1) begin
                sum_reg[i] <= 0;
                carry_reg[i] <= 0;
            end
        end
        else begin
            for (i = 0; i < size; i = i + 1) begin
                sum_reg[i] <= sum_reg_next[i];
                carry_reg[i] <= carry_reg_next[i];
            end
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 0;
        end
        else begin
            mul_out <= sum_reg_next + carry_reg_next;
        end
    end
    always @(*) begin
        for (i = 0; i < size; i = i + 1) begin
            sum_reg_next[i] = sum_reg[i] + partial_product[i] + carry_reg[i];
            carry_reg_next[i] = (sum_reg[i][i] & carry_reg[i]) | (sum_reg[i][i] & partial_product[i][i]) | (carry_reg[i] & partial_product[i][i]);
        end
    end
endmodule

