module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output valid_out,
    output [9:0] data_out
);

reg [9:0] sum;
reg [1:0] count;
reg valid_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        sum <= 10'b0;
        count <= 2'b0;
        valid_out_reg <= 1'b0;
    end
    else if (valid_in) begin
        sum <= sum + data_in;
        count <= count + 1'b1;
        if (count == 2'b11) begin
            valid_out_reg <= 1'b1;
            sum <= 10'b0;
            count <= 2'b0;
        end
        else begin
            valid_out_reg <= 1'b0;
        end
    end
    else begin
        valid_out_reg <= 1'b0;
    end
end

assign data_out = sum;
assign valid_out = valid_out_reg;

endmodule

module right_shifter
(
    input clk,
    input d,
    output reg q
);
initial begin
    q = 8'b00000000;
end
always @(posedge clk) begin
    q <= (q >> 1);
end
assign q[7] = d;
