module synchronizer
(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);
// Register to store data_in
reg [3:0] data_reg;
// Register to store data_en
reg en_data_reg;
// Register to control the MUX selection
reg en_clap_one;
reg en_clap_two;
// Sequential logic to update data_reg on positive edge of clk_a or negative edge of arstn
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        // Reset condition: arstn is low
        data_reg <= 4'b0;
    end else begin
        // Update data_reg with data_in
        data_reg <= data_in;
    end
end
// Sequential logic to update en_data_reg on positive edge of clk_a or negative edge of arstn
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        // Reset condition: arstn is low
        en_data_reg <= 1'b0;
    end else begin
        // Update en_data_reg with data_en
        en_data_reg <= data_en;
    end
end
// Sequential logic to update en_clap_one on positive edge of clk_b or negative edge of brstn
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        // Reset condition: brstn is low
        en_clap_one <= 1'b0;
    end else begin
        // Update en_clap_one with en_data_reg
        en_clap_one <= en_data_reg;
    end
end
// Sequential logic to update en_clap_two on positive edge of clk_b or negative edge of brstn
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        // Reset condition: brstn is low
        en_clap_two <= 1'b0;
    end else begin
        // Update en_clap_two with en_clap_one
        en_clap_two <= en_clap_one;
    end
end
// Output assignment
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        // Reset condition: brstn is low
        dataout <= 4'b0;
    end else begin
        // Assign dataout based on en_clap_two and data_reg
        if (en_clap_two) begin
            dataout <= data_reg;
        end else begin
            dataout <= dataout;
        end
    end
end
endmodule
